php artisan prisoner:add '{"name":"Thomas Lewis","first_name":"Thomas","last_name":"Lewis","description":"Thomas Lewis was a Catholic Worker artist and peace activist, one of the Baltimore 4 (Oct 27, 1967 blood pouring on draft files at the Baltimore Custom House) and one of the Catonsville 9 (May 17, 1968 burning of 378 draft files at the Catonsville Maryland draft board with homemade napalm). He was convicted in October 1968 and sentenced to 3.5 years in federal prison. He served his sentence and continued decades of nonviolent direct action against U.S. militarism. He died on April 4, 2008.","state":"Maryland","race":"White","gender":"Male","death_date":"2008-04-04","ideologies":["Anti-war","Catholic Worker","Pacifism"],"affiliation":["Catonsville 9","Baltimore 4","Catholic Worker"],"era":"1960s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal destruction of government property — Oct 27, 1967 Baltimore Custom House blood pouring (Baltimore 4) and May 17, 1968 Catonsville draft-board raid","arrest_date":"1968-05-17","incarceration_date":"1969-04-09","release_date":"1972-10-09","sentence":"3.5 years federal prison","convicted":"Yes — federal jury verdicts, U.S. District Court for the District of Maryland, 1968"}]}' || true

php artisan prisoner:add '{"name":"Mary Moylan","first_name":"Mary","last_name":"Moylan","description":"Mary Moylan was a Catholic missionary nurse who had served in Uganda before joining the Catholic Left in the United States. She was one of the Catonsville 9 — the May 17, 1968 raid on the Catonsville, Maryland draft board in which 378 draft files were burned with homemade napalm. She was convicted in October 1968 and sentenced to 2 years in federal prison. Rather than report, she went underground in 1970 and lived in clandestinity for nearly ten years before voluntarily surrendering in 1979. She served 18 months at the Alderson Federal Reformatory for Women in West Virginia. She died on August 6, 1995.","state":"Maryland","race":"White","gender":"Female","death_date":"1995-08-06","ideologies":["Anti-war","Catholic","Pacifism"],"affiliation":["Catonsville 9","Women Volunteers Association"],"era":"1960s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Reformatory for Women, Alderson","institution_city":"Alderson","institution_state":"West Virginia","charges":"Federal destruction of government property — May 17, 1968 Catonsville draft-board raid","arrest_date":"1968-05-17","incarceration_date":"1979-08-15","release_date":"1981-02-15","sentence":"2 years federal prison; surrendered after nearly 10 years underground","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Maryland, October 10, 1968"}]}' || true

