php artisan prisoner:add '{"name":"John Schuchardt","first_name":"John","last_name":"Schuchardt","description":"John Schuchardt was a former U.S. Marine Corps officer turned anti-war attorney who became one of the Plowshares 8 — the Catholic Left activists who on September 9, 1980 entered the General Electric Re-Entry Division in King of Prussia, Pennsylvania, hammered nose cones for the Mark 12A nuclear warhead, and poured blood on weapons documents. He was convicted in February 1981 of burglary, conspiracy, trespass, and criminal mischief and sentenced to 3-10 years in Pennsylvania state prison; the sentence was reduced to time served on appeal in April 1990. He went on to co-found the House of Peace community in Ipswich, Massachusetts.","state":"Pennsylvania","race":"White","gender":"Male","ideologies":["Anti-war","Anti-nuclear","Plowshares","Catholic"],"affiliation":["Plowshares 8","U.S. Marine Corps (former)"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Pennsylvania state burglary, conspiracy, trespass, criminal mischief — September 9, 1980 Plowshares 8 hammering of Mark 12A nuclear warhead nose cones at the GE Re-Entry Division in King of Prussia","arrest_date":"1980-09-09","incarceration_date":"1980-09-09","sentence":"3-10 years state prison; reduced to time served on appeal April 1990","convicted":"Yes — Pennsylvania state conviction, February 1981"}]}' || true

php artisan prisoner:add '{"name":"Carl Kabat","first_name":"Carl","last_name":"Kabat","description":"Carl Kabat was an Oblate Catholic priest who became one of the most consistently imprisoned U.S. Plowshares activists, serving an estimated 17 years in federal and state prisons across more than 30 years of symbolic disarmament actions. He was one of the Plowshares 8 — the Catholic Left activists who on September 9, 1980 entered the General Electric Re-Entry Division in King of Prussia, Pennsylvania, hammered nose cones for the Mark 12A nuclear warhead, and poured blood on weapons documents. He was convicted in February 1981 and sentenced to 5-10 years in Pennsylvania state prison. After his release he continued Plowshares actions including the 1984 Silo Pruning Hooks (Minuteman II missile silo, 18 years federal), and the 2009 Disarm Now Plowshares at Bangor Submarine Base. He died on August 4, 2022, age 88.","state":"Pennsylvania","race":"White","gender":"Male","death_date":"2022-08-04","ideologies":["Anti-nuclear","Catholic","Plowshares"],"affiliation":["Missionary Oblates of Mary Immaculate","Plowshares 8","Silo Pruning Hooks"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Pennsylvania state burglary, conspiracy, trespass, criminal mischief — September 9, 1980 Plowshares 8","arrest_date":"1980-09-09","incarceration_date":"1980-09-09","sentence":"5-10 years state prison; reduced on appeal","convicted":"Yes — Pennsylvania state conviction, February 1981"},{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal sabotage and destruction of government property — November 12, 1984 Silo Pruning Hooks action at a Minuteman II missile silo near Whiteman AFB, Missouri","arrest_date":"1984-11-12","incarceration_date":"1984-11-12","sentence":"18 years federal prison (Silo Pruning Hooks)","convicted":"Yes — federal court conviction, 1985"}]}' || true

php artisan prisoner:add '{"name":"Anne Montgomery","first_name":"Anne","last_name":"Montgomery","description":"Anne Montgomery was a Roman Catholic Sacred Heart sister and longtime Plowshares activist. She was one of the Plowshares 8 — the September 9, 1980 King of Prussia, Pennsylvania action against the GE Re-Entry Division and the Mark 12A nuclear warhead. She was convicted in February 1981 and sentenced to 2-5 years in Pennsylvania state prison. She participated in many subsequent Plowshares actions, including the 2009 Disarm Now Plowshares at Bangor Submarine Base in Washington state for which she served 2 months. She died on August 27, 2012, age 86.","state":"Pennsylvania","race":"White","gender":"Female","death_date":"2012-08-27","ideologies":["Anti-nuclear","Catholic","Plowshares"],"affiliation":["Society of the Sacred Heart","Plowshares 8"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Pennsylvania state burglary, conspiracy, trespass, criminal mischief — September 9, 1980 Plowshares 8","arrest_date":"1980-09-09","incarceration_date":"1980-09-09","sentence":"2-5 years state prison","convicted":"Yes — Pennsylvania state conviction, February 1981"}]}' || true

