php artisan prisoner:add '{"name":"Yassin Aref","first_name":"Yassin","middle_name":"M","last_name":"Aref","description":"Yassin Aref is a Kurdish Iraqi imam who came to the United States as a UN refugee in 1999. He was the imam of Masjid As-Salam in Albany, New York at the time of his arrest on August 5, 2004 in an FBI sting operation. The FBI informant Shahed Hussein, posing as an arms dealer, asked pizzeria owner Mohammed Mosharref Hossain to launder money allegedly from the sale of a surface-to-air missile to Jaish-e-Mohammed; Aref was brought in solely as a religious witness to the loan transaction, in accordance with Islamic law on financial agreements.\n\nHe was convicted in October 2006 of conspiracy and money-laundering charges and sentenced in March 2007 to 15 years in federal prison. The 2023 ruling by U.S. District Judge Thomas McAvoy that the FBI informant Shahed Hussein had been a villain whose testimony in unrelated cases warranted relief came too late for Aref, who had already completed his sentence. He was deported to the Iraqi Kurdistan Region after release.","state":"New York","race":"Arab","gender":"Male","ideologies":["Islam","First Amendment"],"affiliation":["Masjid As-Salam (Albany)"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (Communications Management Unit, Terre Haute and Marion)","charges":"Federal conspiracy and money-laundering — Albany pizzeria FBI sting operation, August 2004","arrest_date":"2004-08-05","incarceration_date":"2007-03-08","sentenced_date":"2007-03-08","release_date":"2018-04-15","sentence":"15 years federal prison; subsequently deported to Iraqi Kurdistan","convicted":"Yes — federal jury verdict, U.S. District Court for the Northern District of New York, October 2006"}]}' || true

php artisan prisoner:add '{"name":"Mohammed Mosharref Hossain","first_name":"Mohammed","middle_name":"Mosharref","last_name":"Hossain","description":"Mohammed Mosharref Hossain was the Bangladeshi-American owner of an Albany, New York pizzeria and a founder of the Masjid As-Salam mosque in Albany. He was arrested on August 6, 2004 in an FBI sting operation in which informant Shahed Hussein, posing as an arms dealer, offered him a $50,000 cash loan to be repaid in $45,000 of pizza-shop business checks, with the loaned money allegedly proceeds from the sale of a Chinese surface-to-air missile to Jaish-e-Mohammed for use against the Pakistani Ambassador in New York. Hossain pulled imam Yassin Aref into the transaction solely as a religious witness.\n\nHe was convicted in October 2006 and sentenced in March 2007 to 15 years in federal prison. He was granted compassionate release in June 2020 because of advanced medical risk during the COVID-19 pandemic.","state":"New York","race":"Asian","gender":"Male","ideologies":["Islam","First Amendment"],"affiliation":["Masjid As-Salam (Albany)"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal conspiracy and money-laundering — Albany pizzeria FBI sting operation, August 2004","arrest_date":"2004-08-06","incarceration_date":"2007-03-08","sentenced_date":"2007-03-08","release_date":"2020-06-30","sentence":"15 years federal prison; compassionate release June 2020","convicted":"Yes — federal jury verdict, U.S. District Court for the Northern District of New York, October 2006"}]}' || true

php artisan prisoner:add '{"name":"Syed Fahad Hashmi","first_name":"Syed","middle_name":"Fahad","last_name":"Hashmi","description":"Syed Fahad Hashmi is a Pakistani-American student of Brooklyn College and the London School of Economics. He was arrested on June 6, 2006 at Heathrow Airport on a U.S. federal indictment charging that he had allowed an acquaintance, Junaid Babar, to stay in his London apartment for two weeks in 2004; Babar had brought a suitcase containing socks, ponchos, and waterproof clothing that the indictment characterized as military gear destined for al Qaeda.\n\nHashmi was extradited to the United States in 2007 and held in 23-hour-a-day solitary confinement at the Metropolitan Correctional Center in Manhattan under Special Administrative Measures for nearly three years before trial. The conditions of his pretrial detention drew international condemnation as torture; the case was a foundational one for the Center for Constitutional Rights post-9/11 detention litigation. On April 27, 2010, days before trial, he pleaded guilty to one count of providing material support to al Qaeda and was sentenced to 15 years in federal prison. Most of his sentence was served at the federal Communications Management Units. He was released on July 19, 2019.","state":"New York","race":"Asian","gender":"Male","ideologies":["Islam","First Amendment"],"affiliation":[],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (Communications Management Units)","charges":"Federal conspiracy to provide material support to al Qaeda — alleged 2004 logistical support to Junaid Babar in London","arrest_date":"2006-06-06","incarceration_date":"2007-05-25","sentenced_date":"2010-06-09","release_date":"2019-07-19","sentence":"15 years federal prison","convicted":"Yes — guilty plea, U.S. District Court for the Southern District of New York, April 27, 2010"}]}' || true

